import{_ as a,o as e,c as o,ag as r}from"./chunks/framework.BZohXCq9.js";const h=JSON.parse('{"title":"Categorías e ítems","description":"Cómo organizar tu menú digital con categorías de comida y platos individuales","frontmatter":{"title":"Categorías e ítems","description":"Cómo organizar tu menú digital con categorías de comida y platos individuales"},"headers":[],"relativePath":"food/categorias-e-items.md","filePath":"food/categorias-e-items.md"}'),i={name:"food/categorias-e-items.md"};function n(s,t,d,l,c,u){return e(),o("div",null,[...t[0]||(t[0]=[r('<h2 id="¿que-es" tabindex="-1">¿Qué es? <a class="header-anchor" href="#¿que-es" aria-label="Permalink to &quot;¿Qué es?&quot;">​</a></h2><p>Las categorías e ítems son la estructura fundamental de tu menú en SYNTIfood. Las <strong>categorías</strong> agrupan los platos (ej: &quot;Entradas&quot;, &quot;Platos fuertes&quot;, &quot;Bebidas&quot;) y cada categoría tiene una foto representativa. Los <strong>ítems</strong> son los platos individuales dentro de cada categoría, con nombre y precio.</p><h2 id="¿donde-lo-encuentro" tabindex="-1">¿Dónde lo encuentro? <a class="header-anchor" href="#¿donde-lo-encuentro" aria-label="Permalink to &quot;¿Dónde lo encuentro?&quot;">​</a></h2><p><strong>Tu panel → Qué Vendes</strong> (segundo ícono en el menú lateral, 🛒)</p><h2 id="¿que-hace" tabindex="-1">¿Qué hace? <a class="header-anchor" href="#¿que-hace" aria-label="Permalink to &quot;¿Qué hace?&quot;">​</a></h2><h3 id="categorias" tabindex="-1">Categorías <a class="header-anchor" href="#categorias" aria-label="Permalink to &quot;Categorías&quot;">​</a></h3><p>Cada categoría tiene:</p><ul><li><strong>Nombre</strong> (obligatorio): &quot;Arepas&quot;, &quot;Carnes&quot;, &quot;Jugos&quot;, etc.</li><li><strong>Foto</strong> (1 por categoría): Imagen representativa, máx 2MB, se convierte a WebP</li><li><strong>Orden</strong>: Posición en que aparece en el menú</li></ul><h3 id="items-platos" tabindex="-1">Ítems (platos) <a class="header-anchor" href="#items-platos" aria-label="Permalink to &quot;Ítems (platos)&quot;">​</a></h3><p>Cada ítem dentro de una categoría tiene:</p><ul><li><strong>Nombre</strong> (obligatorio): &quot;Arepa reina pepiada&quot;, &quot;Pabellón criollo&quot;</li><li><strong>Precio</strong> (obligatorio): En REF</li><li><strong>Descripción</strong> (opcional): Ingredientes o detalle corto</li><li><strong>Disponible</strong>: Toggle para marcar como disponible o no</li></ul><h3 id="extras-y-opciones-plan-semestral" tabindex="-1">Extras y opciones (Plan Semestral+) <a class="header-anchor" href="#extras-y-opciones-plan-semestral" aria-label="Permalink to &quot;Extras y opciones (Plan Semestral+)&quot;">​</a></h3><p>Los ítems pueden tener opciones adicionales:</p><ul><li><strong>Tamaño</strong>: Pequeño, mediano, grande</li><li><strong>Punto de cocción</strong>: Término medio, bien cocido</li><li><strong>Extras</strong>: Queso extra, aguacate, papas (REF X adicional)</li></ul><h2 id="¿que-no-hace" tabindex="-1">¿Qué NO hace? <a class="header-anchor" href="#¿que-no-hace" aria-label="Permalink to &quot;¿Qué NO hace?&quot;">​</a></h2><ul><li>No permite foto individual por ítem — solo 1 foto por categoría</li><li>No tiene subcategorías (ej: &quot;Arepas → Rellenas → Especiales&quot;)</li><li>No tiene alérgenos ni información nutricional</li><li>No importa menú desde Excel o PDF</li><li>No tiene precios por tamaño integrados — los extras manejan variaciones</li></ul><h2 id="disponibilidad-por-plan" tabindex="-1">Disponibilidad por plan <a class="header-anchor" href="#disponibilidad-por-plan" aria-label="Permalink to &quot;Disponibilidad por plan&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Característica</th><th>Básico</th><th>Semestral</th><th>Anual</th></tr></thead><tbody><tr><td>Ítems totales</td><td>50</td><td>100</td><td>150</td></tr><tr><td>Fotos de categoría</td><td>6</td><td>12</td><td>18</td></tr><tr><td>Categorías</td><td>❌ (lista plana)</td><td>✅</td><td>✅</td></tr><tr><td>Extras y opciones</td><td>❌</td><td>✅</td><td>✅</td></tr><tr><td>Marcar como no disponible</td><td>✅</td><td>✅</td><td>✅</td></tr></tbody></table><h2 id="ejemplo-practico" tabindex="-1">Ejemplo práctico <a class="header-anchor" href="#ejemplo-practico" aria-label="Permalink to &quot;Ejemplo práctico&quot;">​</a></h2><h3 id="caso-parrilla-el-fogon-en-maracaibo" tabindex="-1">Caso: Parrilla &quot;El Fogón&quot; en Maracaibo <a class="header-anchor" href="#caso-parrilla-el-fogon-en-maracaibo" aria-label="Permalink to &quot;Caso: Parrilla &quot;El Fogón&quot; en Maracaibo&quot;">​</a></h3><p>Luis organiza su menú así:</p><p><strong>Categoría: Carnes a la parrilla</strong> (foto: parrilla humeante)</p><table tabindex="0"><thead><tr><th>Ítem</th><th>Precio</th></tr></thead><tbody><tr><td>Churrasco</td><td>REF 12</td></tr><tr><td>Pollo a la brasa</td><td>REF 8</td></tr><tr><td>Costillas BBQ</td><td>REF 10</td></tr><tr><td>Choripán</td><td>REF 5</td></tr></tbody></table><p><strong>Categoría: Acompañantes</strong> (foto: ensalada y yuca)</p><table tabindex="0"><thead><tr><th>Ítem</th><th>Precio</th></tr></thead><tbody><tr><td>Ensalada mixta</td><td>REF 3</td></tr><tr><td>Yuca frita</td><td>REF 2.50</td></tr><tr><td>Papas fritas</td><td>REF 3</td></tr></tbody></table><p><strong>Categoría: Bebidas</strong> (foto: jarra de limonada)</p><table tabindex="0"><thead><tr><th>Ítem</th><th>Precio</th></tr></thead><tbody><tr><td>Limonada</td><td>REF 2</td></tr><tr><td>Refresco</td><td>REF 1.50</td></tr><tr><td>Cerveza</td><td>REF 3</td></tr></tbody></table><p>Con el plan Semestral, Luis agrega extras al Churrasco: &quot;Punto: Medio / Tres cuartos / Bien cocido&quot; y &quot;Extra queso fundido +REF 2&quot;.</p><p>Total: 10 ítems de su límite de 100, 3 fotos de categoría de su límite de 12.</p><h2 id="ver-tambien" tabindex="-1">Ver también <a class="header-anchor" href="#ver-tambien" aria-label="Permalink to &quot;Ver también&quot;">​</a></h2><ul><li><a href="/food/seccion-menu.html">Sección Menú</a> — Gestión completa de categorías y platos</li><li><a href="/food/extras-opciones.html">Extras y opciones</a> — Personalización de platos</li><li><a href="/food/items-lista.html">Platos y precios</a> — Cómo agregar platos individuales</li></ul>',31)])])}const m=a(i,[["render",n]]);export{h as __pageData,m as default};
